import requests

def download_data(url, outputfile):
    print("Downloading ...")
    r = requests.get(url)
    if r.status_code == 200:
        print(f"Writing to file {outputfile}")
        with open(outputfile, "wb") as f:
            f.write(r.content)
    else:
        print("There was an error in downloaing the file!")


